	/** Operand in generated expressions: g (group id), x (distinct candidate), w<i> (witness column), c<i>. */
	private static final class Op {
		static final int GROUP = 0;
		static final int X = 1;
		static final int WITNESS = 2;
		static final int CONST = 3;

		final int kind;
		final int index; // witness column / constant index
		final int depth; // witness step producing the column, -1 otherwise

		Op(int kind, int index, int depth) {
			this.kind = kind;
			this.index = index;
			this.depth = depth;
		}

		String expr() {
			switch (kind) {
			case GROUP:
				return "g";
			case X:
				return "x";
			case WITNESS:
				return "w" + index;
			default:
				return "c" + index;
			}
		}

		String token() {
			switch (kind) {
			case GROUP:
				return "g";
			case X:
				return "x";
			case WITNESS:
				return "w" + index;
			default:
				return "c";
			}
		}
	}

	private static final class WitnessStep {
		static final int FORWARD = 0; // key known, iterate into a fresh witness column
		static final int CLOSE = 1; // both ends known, existence only

		final int kind;
		final long predicate;
		final boolean bySubject;
		final Op key;
		final Op target; // CLOSE only
		final int column; // FORWARD only

		WitnessStep(int kind, long predicate, boolean bySubject, Op key, Op target, int column) {
			this.kind = kind;
			this.predicate = predicate;
			this.bySubject = bySubject;
			this.key = key;
			this.target = target;
			this.column = column;
		}
	}

	private static final class Guard {
		final Op left;
		final Op right;
		final int depth; // witness step index after which both sides exist; -1 = producer level

		Guard(Op left, Op right, int depth) {
			this.left = left;
			this.right = right;
			this.depth = depth;
		}
	}

	private static final class Recognized {
		long[] domain;
		long producerPredicate;
		boolean producerBySubject;
		final List<WitnessStep> witness = new ArrayList<>();
		final List<Guard> guards = new ArrayList<>();
		final List<Long> constantValues = new ArrayList<>();
		int witnessColumns;
		String shapeKey;
		String className;

		long[] constants() {
			long[] result = new long[constantValues.size()];
			for (int i = 0; i < result.length; i++) {
				result[i] = constantValues.get(i);
			}
			return result;
		}
	}

	private static Recognized recognize(MultiJoinPlan multiJoin, int groupSlot, int distinctSlot, RowState row) {
		SlotPlan[] children = multiJoin.children;
		if (children.length < 2 || children.length > MAX_PATTERNS + 1) {
			return decline("child count " + children.length);
		}
		Recognized shape = new Recognized();
		List<PatternPlan> patterns = new ArrayList<>();
		PatternPlan producerFromValues = null;
		for (SlotPlan child : children) {
			if (child instanceof MultiValuePatternPlan) {
				MultiValuePatternPlan values = (MultiValuePatternPlan) child;
				if (shape.domain != null || values.constrainedSlot != groupSlot
						|| values.alternatives.length == 0) {
					return decline("mvpp: constrainedSlot=" + values.constrainedSlot + " groupSlot=" + groupSlot);
				}
				shape.domain = values.constants.clone();
				producerFromValues = values.alternatives[0];
			} else if (child instanceof ValuesPlan) {
				ValuesPlan values = (ValuesPlan) child;
				if (shape.domain != null || !values.bindsAllSlotsEveryRow || values.rows.length == 0) {
					return decline("valuesPlan not usable");
				}
				long[] ids = new long[values.rows.length];
				for (int i = 0; i < values.rows.length; i++) {
					if (values.rows[i].slots.length != 1 || values.rows[i].slots[0] != groupSlot) {
						return null;
					}
					ids[i] = values.rows[i].values[0];
				}
				shape.domain = ids;
			} else if (child instanceof PatternPlan) {
				patterns.add((PatternPlan) child);
			} else {
				return decline("unsupported child " + child.getClass().getSimpleName());
			}
		}
		if (shape.domain == null) {
			return decline("no VALUES domain child");
		}

		// Find the producer: the pattern binding the distinct slot keyed by the group slot (either from the folded
		// VALUES alternative or among the plain patterns).
		PatternPlan producer = null;
		if (producerFromValues != null) {
			producer = producerFromValues;
		} else {
			for (PatternPlan candidate : patterns) {
				if (touches(candidate, groupSlot) && touches(candidate, distinctSlot)) {
					producer = candidate;
					patterns.remove(candidate);
					break;
				}
			}
		}
		if (producer == null || !basicPatternOk(producer)) {
			return decline(producer == null ? "no producer pattern" : "producer pattern shape unsupported");
		}
		// Producer orientation: group at one end (slot or per-alternative constant at constrainedSlot), distinct at
		// the other.
		boolean groupAtSubject;
		if (slotOf(producer.s) == distinctSlot && endIsGroup(producer.o, groupSlot)) {
			groupAtSubject = false;
		} else if (slotOf(producer.o) == distinctSlot && endIsGroup(producer.s, groupSlot)) {
			groupAtSubject = true;
		} else {
			return decline("producer orientation: sSlot=" + slotOf(producer.s) + " oSlot=" + slotOf(producer.o)
					+ " distinctSlot=" + distinctSlot + " groupSlot=" + groupSlot);
		}
		shape.producerPredicate = producer.p.constant;
		shape.producerBySubject = groupAtSubject;

		// Witness ordering: greedy chain over patterns whose key end is already known (group, x, witness columns).
		StringBuilder key = new StringBuilder("agg1:").append(shape.producerBySubject ? "gs;" : "go;");
		boolean[] used = new boolean[patterns.size()];
		int[] slotOp = new int[row.slots.length]; // -1 unknown, else encoded op
		java.util.Arrays.fill(slotOp, -1);
		long assuredMask = 0L;
		if (producer.s.hasSlot()) {
			assuredMask |= 1L << producer.s.slot;
		}
		slotOp[groupSlot] = encode(Op.GROUP, 0);
		slotOp[distinctSlot] = encode(Op.X, 0);
		int remaining = patterns.size();
		while (remaining > 0) {
			boolean progressed = false;
			for (int i = 0; i < patterns.size(); i++) {
				if (used[i]) {
					continue;
				}
				PatternPlan pattern = patterns.get(i);
				if (!basicPatternOk(pattern)) {
					return decline("witness pattern shape unsupported");
				}
				Op subject = operand(pattern.s, slotOp, shape);
				Op object = operand(pattern.o, slotOp, shape);
				int stepIndex = shape.witness.size();
				if (pattern.s.hasSlot()) {
					assuredMask |= 1L << pattern.s.slot;
				}
				if (subject != null && object != null) {
					shape.witness.add(new WitnessStep(WitnessStep.CLOSE, pattern.p.constant, true, subject, object,
							-1));
					key.append("C(").append(subject.token()).append(',').append(object.token()).append(");");
				} else if (subject != null && pattern.o.hasSlot()) {
					int column = shape.witnessColumns++;
					slotOp[pattern.o.slot] = encode(Op.WITNESS, column);
					shape.witness.add(new WitnessStep(WitnessStep.FORWARD, pattern.p.constant, true, subject, null,
							column));
					key.append("F(").append(subject.token()).append(");");
				} else if (object != null && pattern.s.hasSlot()) {
					int column = shape.witnessColumns++;
					slotOp[pattern.s.slot] = encode(Op.WITNESS, column);
					shape.witness.add(new WitnessStep(WitnessStep.FORWARD, pattern.p.constant, false, object, null,
							column));
					key.append("B(").append(object.token()).append(");");
				} else {
					continue;
				}
				used[i] = true;
				remaining--;
				progressed = true;
			}
			if (!progressed) {
				return decline("disconnected witness pattern"); // no cross products in v1
			}
		}

		// Every filter must become a sound inline id-inequality; there is no residual surface.
		for (MaskedFilter masked : multiJoin.filters) {
			NativeBooleanFilter filter = masked.filter;
			if (filter instanceof RecordingNativeBooleanFilter) {
				filter = ((RecordingNativeBooleanFilter) filter).delegate;
			}
			Guard guard = tryGuard(filter, slotOp, assuredMask, groupSlot, distinctSlot, row, shape);
			if (guard == null) {
				return decline("filter not absorbable: " + filter.getClass().getSimpleName());
			}
			shape.guards.add(guard);
			key.append("ne(")
					.append(guard.left.token())
					.append(',')
					.append(guard.right.token())
					.append('@')
					.append(guard.depth)
					.append(");");
		}

		shape.shapeKey = key.toString();
		shape.className = "org.eclipse.rdf4j.sail.lmdb.gen.AggregateKernel_" + Long.toHexString(fnv(shape.shapeKey));
		return shape;
	}

	private static boolean touches(PatternPlan pattern, int slot) {
		return slotOf(pattern.s) == slot || slotOf(pattern.o) == slot;
	}

	private static boolean basicPatternOk(PatternPlan pattern) {
		return !pattern.hasRepeatedSlot() && !pattern.namedContextScope && pattern.p.isConstant()
				&& !pattern.p.hasSlot() && !pattern.c.hasSlot() && !pattern.c.isConstant()
				&& !pattern.contexts.isFixed();
	}

	private static int slotOf(Term term) {
		return term.hasSlot() && !term.isConstant() ? term.slot : -1;
	}

	private static boolean endIsGroup(Term term, int groupSlot) {
		// Plain slot equal to the group slot, or a folded-VALUES alternative constant that binds the group slot.
		if (term.isConstant()) {
			return !term.hasSlot() || term.slot == groupSlot;
		}
		return term.hasSlot() && term.slot == groupSlot;
	}

	private static int encode(int kind, int index) {
		return kind << 16 | index;
	}

	private static Op operand(Term term, int[] slotOp, Recognized shape) {
		if (term.isConstant() && !term.hasSlot()) {
			shape.constantValues.add(term.constant);
			return new Op(Op.CONST, shape.constantValues.size() - 1, -1);
		}
		if (!term.hasSlot()) {
			return null;
		}
		int encoded = slotOp[term.slot];
		if (encoded < 0) {
			return null;
		}
		int kind = encoded >>> 16;
		int index = encoded & 0xFFFF;
		int depth = kind == Op.WITNESS ? witnessDepthOf(shape, index) : -1;
		return new Op(kind, index, depth);
	}

	private static int witnessDepthOf(Recognized shape, int column) {
		for (int i = 0; i < shape.witness.size(); i++) {
			WitnessStep step = shape.witness.get(i);
			if (step.kind == WitnessStep.FORWARD && step.column == column) {
				return i;
			}
		}
		return -1;
	}

	private static Guard tryGuard(NativeBooleanFilter filter, int[] slotOp, long assuredMask, int groupSlot,
			int distinctSlot, RowState row, Recognized shape) {
		if (filter instanceof OrderedSlotCompareFilter) {
			OrderedSlotCompareFilter compare = (OrderedSlotCompareFilter) filter;
			if (compare.op != Compare.CompareOp.NE) {
				return null;
			}
			boolean sound = (assuredMask >>> compare.leftSlot & 1L) == 1L
					|| (assuredMask >>> compare.rightSlot & 1L) == 1L;
			Op left = opOfSlot(compare.leftSlot, slotOp, shape);
			Op right = opOfSlot(compare.rightSlot, slotOp, shape);
			if (!sound || left == null || right == null) {
				return null;
			}
			return new Guard(left, right, Math.max(left.depth, right.depth));
		}
		if (filter instanceof CachedCompareFilter) {
			CachedCompareFilter compare = (CachedCompareFilter) filter;
			if (compare.op != Compare.CompareOp.NE) {
				return null;
			}
			boolean sound = (assuredMask >>> compare.slot & 1L) == 1L
					|| row.source.lazyValue(compare.constant) instanceof org.eclipse.rdf4j.model.Resource;
			Op slotSide = opOfSlot(compare.slot, slotOp, shape);
			if (!sound || slotSide == null) {
				return null;
			}
			shape.constantValues.add(compare.constant);
			return new Guard(slotSide, new Op(Op.CONST, shape.constantValues.size() - 1, -1), slotSide.depth);
		}
		return null;
	}

	private static Op opOfSlot(int slot, int[] slotOp, Recognized shape) {
		if (slot < 0 || slot >= slotOp.length || slotOp[slot] < 0) {
			return null;
		}
		int encoded = slotOp[slot];
		int kind = encoded >>> 16;
		int index = encoded & 0xFFFF;
		return new Op(kind, index, kind == Op.WITNESS ? witnessDepthOf(shape, index) : -1);
	}

	private static long fnv(String text) {
		long hash = 0xCBF29CE484222325L;
		for (int i = 0; i < text.length(); i++) {
			hash ^= text.charAt(i);
			hash *= 0x100000001B3L;
		}
		return hash;
	}

